import i18n from "i18next";
import { initReactI18next } from "react-i18next";
import LanguageDetector from "i18next-browser-languagedetector";

import es from "./locales/es";
import ca from "./locales/ca";
import en from "./locales/en";
import fr from "./locales/fr";
import de from "./locales/de";
import pt from "./locales/pt";
import it from "./locales/it";
import nl from "./locales/nl";
import ru from "./locales/ru";
import ro from "./locales/ro";
import ar from "./locales/ar";

export const LANGUAGES = [
  { code:"es", label:"EspaГ±ol",    flag:"рџ‡Єрџ‡ё", rtl:false },
  { code:"ca", label:"CatalГ ",     flag:"рџЏґу ЃҐу Ѓіу ЃЈу Ѓґу Ѓї", rtl:false },
  { code:"en", label:"English",    flag:"рџ‡¬рџ‡§", rtl:false },
  { code:"fr", label:"FranГ§ais",   flag:"рџ‡«рџ‡·", rtl:false },
  { code:"de", label:"Deutsch",    flag:"рџ‡©рџ‡Є", rtl:false },
  { code:"pt", label:"PortuguГЄs",  flag:"рџ‡µрџ‡№", rtl:false },
  { code:"it", label:"Italiano",   flag:"рџ‡®рџ‡№", rtl:false },
  { code:"nl", label:"Nederlands", flag:"рџ‡ірџ‡±", rtl:false },
  { code:"ru", label:"Р СѓСЃСЃРєРёР№",    flag:"рџ‡·рџ‡є", rtl:false },
  { code:"ro", label:"RomГўnДѓ",     flag:"рџ‡·рџ‡ґ", rtl:false },
  { code:"ar", label:"Ш§Щ„Ш№Ш±ШЁЩЉШ©",    flag:"рџ‡ёрџ‡¦", rtl:true  },
];

const resources = { es:{t:es}, ca:{t:ca}, en:{t:en}, fr:{t:fr}, de:{t:de}, pt:{t:pt}, it:{t:it}, nl:{t:nl}, ru:{t:ru}, ro:{t:ro}, ar:{t:ar} };

i18n
  .use(LanguageDetector)
  .use(initReactI18next)
  .init({
    resources,
    ns: ["t"],
    defaultNS: "t",
    fallbackLng: "es",          // Spaniola вЂ” limba principala
    lng: localStorage.getItem("jc_lang") || "es",
    interpolation: { escapeValue: false },
    detection: { order: ["localStorage"], lookupLocalStorage: "jc_lang" },
  });

// Aplica directia RTL pt araba
i18n.on("languageChanged", (lng) => {
  const isRtl = LANGUAGES.find(l => l.code === lng)?.rtl || false;
  document.documentElement.setAttribute("dir", isRtl ? "rtl" : "ltr");
  document.documentElement.setAttribute("lang", lng);
  localStorage.setItem("jc_lang", lng);
});

// Seteaza directia la pornire
const initialLang = localStorage.getItem("jc_lang") || "es";
const initialRtl  = LANGUAGES.find(l => l.code === initialLang)?.rtl || false;
document.documentElement.setAttribute("dir", initialRtl ? "rtl" : "ltr");
document.documentElement.setAttribute("lang", initialLang);

export default i18n;
